import React, { useEffect, useState } from 'react';
import { useParams, useSearchParams, useNavigate } from 'react-router-dom';
import CostSummary from '../components/CostSummary';
import { useAuth } from '../context/AuthContext';
import { getApiBase } from '../api/client';

function parseIntParam(n, def, min, max) {
  const v = Number(n);
  if (Number.isFinite(v) && v >= min && v <= max) return v;
  return def;
}

export default function TripDetails() {
  const { id } = useParams();
  const [searchParams] = useSearchParams();
  const [dest, setDest] = useState(null);
  const [days, setDays] = useState(() => parseIntParam(new URLSearchParams(window.location.search).get('days'), 3, 1, 30));
  const [queryTotalBudget, setQueryTotalBudget] = useState(() => {
    const t = new URLSearchParams(window.location.search).get('total_budget_pkr');
    if (!t) return null;
    const n = Number(t);
    return Number.isFinite(n) && n > 0 ? n : null;
  });
  const { user, toggleSaveTrip } = useAuth();
  const navigate = useNavigate();
  const [saved, setSaved] = useState(false);
  const [plan, setPlan] = useState(null);
  const [saveStatus, setSaveStatus] = useState('');
  const [planNotes, setPlanNotes] = useState('');

  useEffect(() => {
    fetch(`${getApiBase()}/api/destinations/${id}`)
      .then((r) => (r.ok ? r.json() : null))
      .then((d) => setDest(d))
      .catch(() => setDest(null));
  }, [id]);

  useEffect(() => {
    setDays(parseIntParam(searchParams.get('days'), 3, 1, 30));
    const t = searchParams.get('total_budget_pkr');
    if (t) {
      const n = Number(t);
      setQueryTotalBudget(Number.isFinite(n) && n > 0 ? n : null);
    } else {
      setQueryTotalBudget(null);
    }
  }, [id, searchParams]);

  useEffect(() => {
    if (!dest) return;
    if (user && user.saved) setSaved(user.saved.includes(String(dest.id)));
    else setSaved(false);
  }, [dest, user]);

  if (!dest) {
    return (
      <div className="page page-trip">
        <h2>{id ? 'Loading destination…' : 'Destination not found'}</h2>
      </div>
    );
  }

  const image =
    dest.image ||
    'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1200&q=60';

  async function handleSave() {
    if (!user) {
      try {
        localStorage.setItem('pending_save', JSON.stringify({ id: dest.id, redirect: window.location.pathname }));
      } catch (e) {}
      navigate('/login');
      return;
    }

    const list = await toggleSaveTrip(dest.id);
    if (list) setSaved(list.includes(String(dest.id)));
  }

  function saveFullPlan() {
    if (!user) {
      navigate('/login');
      return;
    }
    const totalBudgetPkr =
      queryTotalBudget != null && queryTotalBudget > 0
        ? queryTotalBudget
        : dest.cost
          ? dest.cost * days
          : null;
    const perDay = totalBudgetPkr && days > 0 ? Math.round(totalBudgetPkr / days) : null;
    const autoHint = [
      `Plan for ${days} day(s)`,
      totalBudgetPkr != null ? `total trip budget about ${totalBudgetPkr} PKR` : null,
      perDay != null ? `around ${perDay} PKR per day` : null,
    ]
      .filter(Boolean)
      .join('; ');
    const user_message = [planNotes.trim(), autoHint].filter(Boolean).join('. ');
    setSaveStatus('Saving…');
    fetch(`${getApiBase()}/api/trips/plan`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        user_id: user.id,
        destination_id: dest.id,
        days,
        total_budget_pkr: totalBudgetPkr,
        user_message: user_message || undefined,
      }),
    })
      .then((r) => r.json())
      .then((data) => {
        if (data.itinerary) setPlan(data.itinerary);
        const extra = data.planner === 'places_catalog_groq' ? ' (from your places + Groq)' : '';
        setSaveStatus(
          data.trip_id ? `Saved as trip #${data.trip_id}${extra}` : data.message || 'Done'
        );
      })
      .catch(() => setSaveStatus('Could not save'))
      .finally(() => {
        setTimeout(() => setSaveStatus(''), 4000);
      });
  }

  const lat = dest.latitude;
  const lon = dest.longitude;
  const mapSrc =
    lat && lon
      ? `https://www.openstreetmap.org/export/embed.html?bbox=${lon - 0.15}%2C${lat - 0.1}%2C${lon + 0.15}%2C${lat + 0.1}&layer=mapnik&marker=${lat}%2C${lon}`
      : null;

  const displayPlan = plan;

  return (
    <div className="page page-trip">
      <div className="trip-header">
        <div className="trip-image" style={{ backgroundImage: `url(${image})` }} />
        <div className="trip-meta">
          <h1>{dest.name}</h1>
          <div className="muted">
            {dest.region} • {dest.type || dest.category}
          </div>
          <div style={{ marginTop: 8 }}>
            <button type="button" className={saved ? 'btn saved' : 'btn'} onClick={handleSave}>
              {saved ? 'Saved' : 'Save'}
            </button>
          </div>
        </div>
      </div>

      <div className="trip-body">
        <div className="trip-left">
          <h3>Overview</h3>
          <p className="muted">{dest.summary || dest.description || 'A great place to visit in Pakistan.'}</p>

          {mapSrc && (
            <div style={{ marginTop: 12 }}>
              <h4>Map</h4>
              <iframe title="map" width="100%" height="220" style={{ border: 0 }} src={mapSrc} />
              <p className="muted small">OpenStreetMap embed (no API key).</p>
            </div>
          )}

          <h4 style={{ marginTop: 12 }}>Duration (days)</h4>
          {queryTotalBudget != null && days > 0 && (
            <p className="muted small">
              From your search: total budget about {queryTotalBudget.toLocaleString()} PKR · ≈{Math.round(queryTotalBudget / days).toLocaleString()} PKR / day
            </p>
          )}
          <select value={days} onChange={(e) => setDays(Number(e.target.value))}>
            {[1, 2, 3, 4, 5, 6, 7, 8, 10, 14].map((n) => (
              <option key={n} value={n}>
                {n} {n === 1 ? 'day' : 'days'}
              </option>
            ))}
          </select>

          <h4 style={{ marginTop: 12 }}>Plan preferences (optional)</h4>
          <p className="muted small">Groq will use real hotels, restaurants, and spots from the places table (with PKR costs) when available.</p>
          <textarea
            className="auth-form"
            style={{ width: '100%', minHeight: 64, boxSizing: 'border-box' }}
            placeholder="e.g. stay under 15,000 per night, local food, visit Daman-e-Koh"
            value={planNotes}
            onChange={(e) => setPlanNotes(e.target.value)}
          />

          <div style={{ marginTop: 12 }}>
            <button type="button" className="btn-outline" onClick={saveFullPlan}>
              Generate &amp; save plan (AI itinerary)
            </button>
            {saveStatus && <span className="muted" style={{ marginLeft: 8 }}>{saveStatus}</span>}
          </div>

          <h4 style={{ marginTop: 12 }}>Itinerary</h4>
          <p className="muted small">Click the button above to build a day-by-day plan (Groq) and save it to your account.</p>
          <div className="itinerary">
            {(displayPlan || mockLocalItinerary(dest, days)).map((day) => (
              <div key={day.day_number} className="it-day">
                <strong>Day {day.day_number}</strong>
                {(day.items || day.lines || []).map((line, i) => (
                  <div key={i} className="muted">
                    {typeof line === 'string' ? line : line.title}
                    {typeof line === 'object' && line && line.estimated_cost_pkr > 0 && (
                      <span> — ~{line.estimated_cost_pkr} PKR</span>
                    )}
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>

        <aside className="trip-right">
          <h3>Cost Estimate</h3>
          <CostSummary dest={dest} duration={days} />

          <div style={{ marginTop: 12 }}>
            <h4>Details</h4>
            <div className="muted">Best season: {dest.best_season}</div>
            <div className="muted">Climate: {dest.weather || dest.climate}</div>
            <div className="muted">User rating: {dest.user_rating}</div>
          </div>
        </aside>
      </div>
    </div>
  );
}

function mockLocalItinerary(dest, dayCount) {
  const n = Math.min(Math.max(1, dayCount), 7);
  const base = (dest.tags && dest.tags[0]) || 'sightseeing';
  const out = [];
  for (let d = 1; d <= n; d += 1) {
    out.push({
      day_number: d,
      items: [
        { title: `Day ${d}: ${base} around ${dest.name}` },
        { title: d === 1 ? 'Arrival, hotel check-in' : 'Explore local spots' },
      ],
    });
  }
  return out;
}
